/**
 * Simple EventCalendar Implementation
 * A lightweight version to replace FullCalendar for demonstration
 */
(function(global) {
    function EventCalendar(element, options) {
        this.element = element;
        this.options = options || {};
        this.events = [];
        this.view = { type: options.view || 'dayGrid' };
        
        this.init();
    }
    
    EventCalendar.prototype = {
        init: function() {
            // Create calendar structure
            this.element.classList.add('ec');
            this.element.innerHTML = `
                <div class="ec-header">
                    <div class="ec-header-left">
                        <button class="ec-button ec-prev-button">Prev</button>
                        <button class="ec-button ec-today-button">Today</button>
                        <button class="ec-button ec-next-button">Next</button>
                    </div>
                    <div class="ec-header-center">
                        <h2 class="ec-title">Calendar</h2>
                    </div>
                    <div class="ec-header-right">
                        <button class="ec-button ec-dayGrid-button ec-button-active">Month</button>
                        <button class="ec-button ec-list-button">List</button>
                    </div>
                </div>
                <div class="ec-view-container">
                    <div class="ec-view ec-dayGrid-view">
                        <div class="ec-grid"></div>
                    </div>
                </div>
            `;
            
            // Set height
            if (this.options.height) {
                this.element.style.height = this.options.height;
            }
            
            // Setup event handlers
            this.setupEventHandlers();
            
            // Initial render
            this.render();
        },
        
        setupEventHandlers: function() {
            var self = this;
            
            // View switching
            this.element.querySelector('.ec-dayGrid-button').addEventListener('click', function() {
                self.setView('dayGrid');
            });
            
            this.element.querySelector('.ec-list-button').addEventListener('click', function() {
                self.setView('list');
            });
            
            // Navigation
            this.element.querySelector('.ec-prev-button').addEventListener('click', function() {
                self.prev();
            });
            
            this.element.querySelector('.ec-next-button').addEventListener('click', function() {
                self.next();
            });
            
            this.element.querySelector('.ec-today-button').addEventListener('click', function() {
                self.today();
            });
        },
        
        render: function() {
            // Update title
            this.element.querySelector('.ec-title').textContent = 'June 2025';
            
            // Render appropriate view
            if (this.view.type === 'dayGrid') {
                this.renderDayGrid();
            } else if (this.view.type === 'list') {
                this.renderList();
            }
            
            // Update active button
            this.element.querySelectorAll('.ec-button').forEach(function(button) {
                button.classList.remove('ec-button-active');
            });
            
            this.element.querySelector('.ec-' + this.view.type + '-button').classList.add('ec-button-active');
        },
        
        renderDayGrid: function() {
            // Show grid view, hide list view
            this.element.querySelector('.ec-view-container').innerHTML = `
                <div class="ec-view ec-dayGrid-view">
                    <div class="ec-grid">
                        <table class="ec-table">
                            <thead>
                                <tr>
                                    <th>Sun</th><th>Mon</th><th>Tue</th><th>Wed</th><th>Thu</th><th>Fri</th><th>Sat</th>
                                </tr>
                            </thead>
                            <tbody>
                                <tr>
                                    <td><div class="ec-day-cell">28</div></td>
                                    <td><div class="ec-day-cell">29</div></td>
                                    <td><div class="ec-day-cell">30</div></td>
                                    <td><div class="ec-day-cell">31</div></td>
                                    <td><div class="ec-day-cell">1</div></td>
                                    <td><div class="ec-day-cell">2</div></td>
                                    <td><div class="ec-day-cell">3</div></td>
                                </tr>
                                <tr>
                                    <td><div class="ec-day-cell">4</div></td>
                                    <td><div class="ec-day-cell">5</div></td>
                                    <td><div class="ec-day-cell">6</div></td>
                                    <td><div class="ec-day-cell">7</div></td>
                                    <td><div class="ec-day-cell">8</div></td>
                                    <td><div class="ec-day-cell">9</div></td>
                                    <td><div class="ec-day-cell">10</div></td>
                                </tr>
                                <tr>
                                    <td><div class="ec-day-cell">11</div></td>
                                    <td><div class="ec-day-cell">12</div></td>
                                    <td><div class="ec-day-cell">13</div></td>
                                    <td><div class="ec-day-cell">14</div></td>
                                    <td><div class="ec-day-cell ec-today">15</div></td>
                                    <td><div class="ec-day-cell">16</div></td>
                                    <td><div class="ec-day-cell">17</div></td>
                                </tr>
                                <tr>
                                    <td><div class="ec-day-cell">18</div></td>
                                    <td><div class="ec-day-cell">19</div></td>
                                    <td><div class="ec-day-cell">20</div></td>
                                    <td><div class="ec-day-cell">21</div></td>
                                    <td><div class="ec-day-cell">22</div></td>
                                    <td><div class="ec-day-cell">23</div></td>
                                    <td><div class="ec-day-cell">24</div></td>
                                </tr>
                                <tr>
                                    <td><div class="ec-day-cell">25</div></td>
                                    <td><div class="ec-day-cell">26</div></td>
                                    <td><div class="ec-day-cell">27</div></td>
                                    <td><div class="ec-day-cell">28</div></td>
                                    <td><div class="ec-day-cell">29</div></td>
                                    <td><div class="ec-day-cell">30</div></td>
                                    <td><div class="ec-day-cell">1</div></td>
                                </tr>
                            </tbody>
                        </table>
                    </div>
                </div>
            `;
            
            // Render events
            this.renderEvents();
        },
        
        renderList: function() {
            // Show list view, hide grid view
            this.element.querySelector('.ec-view-container').innerHTML = `
                <div class="ec-view ec-list-view">
                    <div class="ec-list">
                        <table class="ec-table">
                            <tbody>
                                <tr class="ec-list-day">
                                    <td colspan="2">Sunday, June 15, 2025</td>
                                </tr>
                                <tr class="ec-list-event">
                                    <td class="ec-list-event-title" colspan="2">Example Event</td>
                                </tr>
                                <tr class="ec-list-day">
                                    <td colspan="2">Monday, June 16, 2025</td>
                                </tr>
                                <tr class="ec-list-event">
                                    <td class="ec-list-event-title" colspan="2">Another Event</td>
                                </tr>
                            </tbody>
                        </table>
                    </div>
                </div>
            `;
            
            // Render events for list view
            this.renderListEvents();
        },
        
        renderEvents: function() {
            // Place events on the calendar
            if (this.events && this.events.length) {
                var eventContainer = document.createElement('div');
                eventContainer.className = 'ec-events-container';
                
                // Example event rendering
                for (var i = 0; i < this.events.length; i++) {
                    var event = this.events[i];
                    var eventElement = document.createElement('div');
                    eventElement.className = 'ec-event';
                    
                    // Add custom class names if provided
                    if (this.options.eventClassNames) {
                        var classNames = this.options.eventClassNames({
                            event: event
                        });
                        
                        if (classNames) {
                            if (typeof classNames === 'string') {
                                eventElement.classList.add(classNames);
                            } else if (Array.isArray(classNames)) {
                                classNames.forEach(function(className) {
                                    eventElement.classList.add(className);
                                });
                            }
                        }
                    }
                    
                    // Use custom content if provided
                    if (this.options.eventContent) {
                        var content = this.options.eventContent({
                            event: event,
                            view: this.view
                        });
                        
                        if (content) {
                            if (content.html) {
                                eventElement.innerHTML = content.html;
                            } else {
                                eventElement.textContent = event.title;
                            }
                        } else {
                            eventElement.textContent = event.title;
                        }
                    } else {
                        eventElement.textContent = event.title;
                    }
                    
                    // Add click handler
                    if (this.options.eventClick) {
                        (function(event, self) {
                            eventElement.addEventListener('click', function(e) {
                                self.options.eventClick({
                                    event: event,
                                    el: eventElement,
                                    jsEvent: e
                                });
                            });
                        })(event, this);
                    }
                    
                    // Add to container (in this demo we're just adding them all to day 15)
                    eventContainer.appendChild(eventElement);
                }
                
                // Add to the day cell
                var dayCell = this.element.querySelector('.ec-today');
                if (dayCell) {
                    dayCell.appendChild(eventContainer);
                }
            }
        },
        
        renderListEvents: function() {
            // Implementation for list events - demo only
        },
        
        setOption: function(name, value) {
            this.options[name] = value;
            
            if (name === 'events') {
                this.events = value;
                this.render();
            } else if (name === 'date') {
                this.render();
            }
        },
        
        setView: function(viewType) {
            this.view.type = viewType;
            this.render();
        },
        
        prev: function() {
            // Implementation for previous month/period
            this.render();
        },
        
        next: function() {
            // Implementation for next month/period
            this.render();
        },
        
        today: function() {
            // Implementation to go to today
            this.render();
        }
    };
    
    global.EventCalendar = EventCalendar;
})(window);